2081 /// Given a bitwise logic op, check if the operands are add/sub with a common
2082 /// source value and inverted constant (identity: C - X -> ~(X + ~C)).
2083 static Value *simplifyLogicOfAddSub(Value *Op0, Value *Op1,
2084                                     Instruction::BinaryOps Opcode) {
2085   assert(Op0->getType() == Op1->getType() && "Mismatched binop types");
2086   assert(BinaryOperator::isBitwiseLogicOp(Opcode) && "Expected logic op");
2087   Value *X;
2088   Constant *C1, *C2;
2089   if ((match(Op0, m_Add(m_Value(X), m_Constant(C1))) &&
2090        match(Op1, m_Sub(m_Constant(C2), m_Specific(X)))) ||
2091       (match(Op1, m_Add(m_Value(X), m_Constant(C1))) &&
2092        match(Op0, m_Sub(m_Constant(C2), m_Specific(X))))) {
2093     if (ConstantExpr::getNot(C1) == C2) {
2094       // (X + C) & (~C - X) --> (X + C) & ~(X + C) --> 0
2095       // (X + C) | (~C - X) --> (X + C) | ~(X + C) --> -1
2096       // (X + C) ^ (~C - X) --> (X + C) ^ ~(X + C) --> -1
2097       Type *Ty = Op0->getType();
2098       return Opcode == Instruction::And ? ConstantInt::getNullValue(Ty)
2099                                         : ConstantInt::getAllOnesValue(Ty);
2100     }
2101   }
2102   return nullptr;
2103 }
