2615 
2616   // A ^ undef -> undef
2617   if (Q.isUndefValue(Op1))
2618     return Op1;
2619 
2620   // A ^ 0 = A
2621   if (match(Op1, m_Zero()))
2622     return Op0;
2623 
2624   // A ^ A = 0
2625   if (Op0 == Op1)
2626     return Constant::getNullValue(Op0->getType());
2627 
2628   // A ^ ~A  =  ~A ^ A  =  -1
2629   if (match(Op0, m_Not(m_Specific(Op1))) || match(Op1, m_Not(m_Specific(Op0))))
2630     return Constant::getAllOnesValue(Op0->getType());
2631 
2632   auto foldAndOrNot = [](Value *X, Value *Y) -> Value * {
2633     Value *A, *B;
2634     // (~A & B) ^ (A | B) --> A -- There are 8 commuted variants.
2635     if (match(X, m_c_And(m_Not(m_Value(A)), m_Value(B))) &&
2636         match(Y, m_c_Or(m_Specific(A), m_Specific(B))))
2637       return A;
2638 
2639     // (~A | B) ^ (A & B) --> ~A -- There are 8 commuted variants.
2640     // The 'not' op must contain a complete -1 operand (no undef elements for
2641     // vector) for the transform to be safe.
2642     Value *NotA;
2643     if (match(X,
2644               m_c_Or(m_CombineAnd(m_NotForbidUndef(m_Value(A)), m_Value(NotA)),
2645                      m_Value(B))) &&
2646         match(Y, m_c_And(m_Specific(A), m_Specific(B))))
2647       return NotA;
2648 
2649     return nullptr;
2650   };
2651   if (Value *R = foldAndOrNot(Op0, Op1))
2652     return R;
2653   if (Value *R = foldAndOrNot(Op1, Op0))
2654     return R;
