4547 
4548   // (X & Y) == 0 ? X : X & ~Y  --> X & ~Y
4549   // (X & Y) != 0 ? X : X & ~Y  --> X
4550   if (TrueVal == X && match(FalseVal, m_And(m_Specific(X), m_APInt(C))) &&
4551       *Y == ~*C)
4552     return TrueWhenUnset ? FalseVal : TrueVal;
4553 
4554   if (Y->isPowerOf2()) {
4555     // (X & Y) == 0 ? X | Y : X  --> X | Y
4556     // (X & Y) != 0 ? X | Y : X  --> X
4557     if (FalseVal == X && match(TrueVal, m_Or(m_Specific(X), m_APInt(C))) &&
4558         *Y == *C)
4559       return TrueWhenUnset ? TrueVal : FalseVal;
4560 
4561     // (X & Y) == 0 ? X : X | Y  --> X
4562     // (X & Y) != 0 ? X : X | Y  --> X | Y
4563     if (TrueVal == X && match(FalseVal, m_Or(m_Specific(X), m_APInt(C))) &&
4564         *Y == *C)
4565       return TrueWhenUnset ? TrueVal : FalseVal;
4566   }
4567 
4568   return nullptr;
