4536 /// Try to simplify a select instruction when its condition operand is an
4537 /// integer comparison where one operand of the compare is a constant.
4538 static Value *simplifySelectBitTest(Value *TrueVal, Value *FalseVal, Value *X,
4539                                     const APInt *Y, bool TrueWhenUnset) {
4540   const APInt *C;
