4633   // (X <= Y) ? X : max(X, Y) --> X
4634   // (X >  Y) ? X : min(X, Y) --> X
4635   // (X >= Y) ? X : min(X, Y) --> X
4636   ICmpInst::Predicate InvPred = CmpInst::getInversePredicate(Pred);
4637   if (MMPred == CmpInst::getStrictPredicate(InvPred))
