4464     }
4465 
4466     if (isa<GetElementPtrInst>(I)) {
4467       // getelementptr x, 0 -> x.
4468       // This never returns poison, even if inbounds is set.
4469       if (NewOps.size() == 2 && match(NewOps[1], m_Zero()))
4470         return NewOps[0];
4471     }
4472   } else {
4473     // The simplification queries below may return the original value. Consider:
4474     //   %div = udiv i32 %arg, %arg2
4475     //   %mul = mul nsw i32 %div, %arg2
4476     //   %cmp = icmp eq i32 %mul, %arg
4477     //   %sel = select i1 %cmp, i32 %div, i32 undef
4478     // Replacing %arg by %mul, %div becomes "udiv i32 %mul, %arg2", which
4479     // simplifies back to %arg. This can only happen because %mul does not
4480     // dominate %div. To ensure a consistent return value contract, we make sure
4481     // that this case returns nullptr as well.
4482     auto PreventSelfSimplify = [V](Value *Simplified) {
4483       return Simplified != V ? Simplified : nullptr;
4484     };
4485 
4486     return PreventSelfSimplify(
4487         ::simplifyInstructionWithOperands(I, NewOps, Q, MaxRecurse));
4488   }
4489 
4490   // If all operands are constant after substituting Op for RepOp then we can
4491   // constant fold the instruction.
4492   SmallVector<Constant *, 8> ConstOps;
4493   for (Value *NewOp : NewOps) {
4494     if (Constant *ConstOp = dyn_cast<Constant>(NewOp))
4495       ConstOps.push_back(ConstOp);
4496     else
4497       return nullptr;
4498   }
4499 
4500   // Consider:
4501   //   %cmp = icmp eq i32 %x, 2147483647
4502   //   %add = add nsw i32 %x, 1
4503   //   %sel = select i1 %cmp, i32 -2147483648, i32 %add
4504   //
4505   // We can't replace %sel with %add unless we strip away the flags (which
4506   // will be done in InstCombine).
4507   // TODO: This may be unsound, because it only catches some forms of
4508   // refinement.
4509   if (!AllowRefinement) {
4510     if (canCreatePoison(cast<Operator>(I), !DropFlags)) {
4511       // abs cannot create poison if the value is known to never be int_min.
4512       if (auto *II = dyn_cast<IntrinsicInst>(I);
4513           II && II->getIntrinsicID() == Intrinsic::abs) {
4514         if (!ConstOps[0]->isNotMinSignedValue())
4515           return nullptr;
4516       } else
4517         return nullptr;
4518     }
4519     Constant *Res = ConstantFoldInstOperands(I, ConstOps, Q.DL, Q.TLI);
4520     if (DropFlags && Res && I->hasPoisonGeneratingFlagsOrMetadata())
4521       DropFlags->push_back(I);
4522     return Res;
4523   }
4524 
4525   return ConstantFoldInstOperands(I, ConstOps, Q.DL, Q.TLI);
4526 }
